import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import axios from 'axios';
import { Upload, FileText, Users, MessageSquare, Download } from 'lucide-react';

const Classroom = () => {
  const [classData, setClassData] = useState(null);
  const [files, setFiles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [uploadFile, setUploadFile] = useState(null);
  const [uploadData, setUploadData] = useState({
    description: '',
    category: 'general'
  });

  const { id } = useParams();
  const { user } = useAuth();

  useEffect(() => {
    fetchClassData();
    fetchFiles();
  }, [id]);

  const fetchClassData = async () => {
    try {
      const response = await axios.get(`/classes/${id}`);
      setClassData(response.data.data.class);
    } catch (error) {
      console.error('Error fetching class data:', error);
    }
  };

  const fetchFiles = async () => {
    try {
      const response = await axios.get(`/files/class/${id}`);
      setFiles(response.data.data.files);
    } catch (error) {
      console.error('Error fetching files:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (e) => {
    e.preventDefault();
    if (!uploadFile) return;

    const formData = new FormData();
    formData.append('file', uploadFile);
    formData.append('classId', id);
    formData.append('description', uploadData.description);
    formData.append('category', uploadData.category);

    try {
      const response = await axios.post('/files/upload', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      
      setFiles(prev => [response.data.data.file, ...prev]);
      setShowUploadModal(false);
      setUploadFile(null);
      setUploadData({ description: '', category: 'general' });
    } catch (error) {
      console.error('Error uploading file:', error);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (!classData) {
    return <div>Class not found</div>;
  }

  return (
    <div className="max-w-6xl mx-auto">
      {/* Class Header */}
      <div className="mb-8">
        <div 
          className="h-4 rounded-t-lg mb-4"
          style={{ backgroundColor: classData.color }}
        ></div>
        <div className="flex items-start justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">
              {classData.name}
            </h1>
            <p className="text-gray-600 mb-4">
              {classData.description}
            </p>
            <div className="flex items-center space-x-4 text-sm text-gray-500">
              <div className="flex items-center">
                <Users className="w-4 h-4 mr-1" />
                <span>
                  {classData.teacher.name} • {classData.students.length} students
                </span>
              </div>
              <span>Code: {classData.code}</span>
            </div>
          </div>
          
          {user?.role === 'teacher' && (
            <button
              onClick={() => setShowUploadModal(true)}
              className="btn btn-primary flex items-center"
            >
              <Upload className="w-4 h-4 mr-2" />
              Upload File
            </button>
          )}
        </div>
      </div>

      {/* Files Section */}
      <div className="card">
        <h2 className="text-xl font-bold mb-4">Class Files</h2>
        
        {files.length === 0 ? (
          <div className="text-center py-8 text-gray-500">
            <FileText className="w-16 h-16 mx-auto mb-4 text-gray-300" />
            <p>No files uploaded yet</p>
            {user?.role === 'teacher' && (
              <p className="text-sm">Upload the first file to get started</p>
            )}
          </div>
        ) : (
          <div className="space-y-3">
            {files.map(file => (
              <div key={file._id} className="flex items-center justify-between p-4 border border-gray-200 rounded-lg hover:bg-gray-50">
                <div className="flex items-center space-x-4">
                  <FileText className="w-8 h-8 text-blue-500" />
                  <div>
                    <h3 className="font-medium text-gray-900">
                      {file.originalName}
                    </h3>
                    <p className="text-sm text-gray-500">
                      Uploaded by {file.uploadedBy.name} • 
                      {new Date(file.createdAt).toLocaleDateString()} • 
                      {(file.size / 1024 / 1024).toFixed(2)} MB
                    </p>
                    {file.description && (
                      <p className="text-sm text-gray-600 mt-1">
                        {file.description}
                      </p>
                    )}
                  </div>
                </div>
                
                <div className="flex items-center space-x-2">
                  <span className="bg-gray-100 px-2 py-1 rounded text-xs capitalize">
                    {file.category}
                  </span>
                  <a
                    href={`http://localhost:5000/${file.path}`}
                    download
                    className="btn btn-secondary p-2"
                  >
                    <Download className="w-4 h-4" />
                  </a>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Upload Modal */}
      {showUploadModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <div className="card max-w-md w-full">
            <h2 className="text-xl font-bold mb-4">Upload File</h2>
            <form onSubmit={handleFileUpload}>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Select File
                  </label>
                  <input
                    type="file"
                    onChange={(e) => setUploadFile(e.target.files[0])}
                    className="input"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Description
                  </label>
                  <input
                    type="text"
                    value={uploadData.description}
                    onChange={(e) => setUploadData(prev => ({ ...prev, description: e.target.value }))}
                    className="input"
                    placeholder="File description..."
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Category
                  </label>
                  <select
                    value={uploadData.category}
                    onChange={(e) => setUploadData(prev => ({ ...prev, category: e.target.value }))}
                    className="input"
                  >
                    <option value="general">General</option>
                    <option value="timetable">Timetable</option>
                    <option value="notice">Notice</option>
                    <option value="study-material">Study Material</option>
                    <option value="exam">Exam</option>
                    <option value="image">Image</option>
                  </select>
                </div>
              </div>

              <div className="flex space-x-3 mt-6">
                <button
                  type="submit"
                  className="flex-1 btn btn-primary"
                  disabled={!uploadFile}
                >
                  Upload File
                </button>
                <button
                  type="button"
                  onClick={() => setShowUploadModal(false)}
                  className="flex-1 btn btn-secondary"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Classroom;
